import{_ as a,o as e,c as t,a2 as i}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"G10: 關鍵合作夥伴與Tier1客戶 - 投資研究員審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/8064_東捷/20260429/G10_關鍵合作夥伴與Tier1客戶_投資研究員.md","filePath":"審計報告庫/經營審計/8064_東捷/20260429/G10_關鍵合作夥伴與Tier1客戶_投資研究員.md"}'),o={name:"審計報告庫/經營審計/8064_東捷/20260429/G10_關鍵合作夥伴與Tier1客戶_投資研究員.md"};function l(n,r,s,h,c,_){return e(),t("div",null,[...r[0]||(r[0]=[i('<h1 id="g10-關鍵合作夥伴與tier1客戶-投資研究員審計報告" tabindex="-1">G10: 關鍵合作夥伴與Tier1客戶 - 投資研究員審計報告 <a class="header-anchor" href="#g10-關鍵合作夥伴與tier1客戶-投資研究員審計報告" aria-label="Permalink to &quot;G10: 關鍵合作夥伴與Tier1客戶 - 投資研究員審計報告&quot;">​</a></h1><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的投資洞見。</p><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>公司是否擁有具備國際指標性的關鍵合作夥伴或 Tier1 客戶？這類關係的穩定度與進入壁壘為何？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li>核心結論：東捷以群創FOPLP鏈結日月光，未取得國際CSP認證，Tier1位階屬二線設備。 風險評級：中 數據時效：截至2025年年報及2026年4月</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>： <ul><li>三大客戶佔比49%→28%，集中度改善；中國營收佔比28%→52%</li><li>半導體設備佔比15-20%，Q4單季營收10.8億（年增76%）</li></ul></li><li><strong>診斷見解</strong>：集中度改善源於群創FOPLP放量與LED擴張。但地域翻轉「中國過半」，地緣政治與匯率風險同步放大。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="關鍵合作夥伴與tier1客戶識別" tabindex="-1">關鍵合作夥伴與Tier1客戶識別 <a class="header-anchor" href="#關鍵合作夥伴與tier1客戶識別" aria-label="Permalink to &quot;關鍵合作夥伴與Tier1客戶識別&quot;">​</a></h3><ul><li><strong>核心重點</strong>：直供群創光電（FOPLP雷射修補機、AOI）、日月光投控、力成。間接鏈結台積電CoWoS。G2C+聯盟含志聖、均豪、均華。</li><li><strong>深度見解</strong>：群創為核心Tier1，2026年3月已取得RDL及TGV認證。日月光以148.5億收購群創南科Fab 5，東捷間接受惠。但非Sole Source，替代風險存在。</li></ul><h3 id="關係穩定度與進入壁壘" tabindex="-1">關係穩定度與進入壁壘 <a class="header-anchor" href="#關係穩定度與進入壁壘" aria-label="Permalink to &quot;關係穩定度與進入壁壘&quot;">​</a></h3><ul><li><strong>核心重點</strong>：合約1-2年滾動式，無LTA。NPI驗證6-18個月。OHS獲SEMI E187國際資安認證。</li><li><strong>深度見解</strong>：進入壁壘中等——雷射+真空鍍膜+自動化複合能力構成門檻，同業（志聖、均豪）具相似能力。護城河在「產線深度整合經驗」，替換含重新驗證與停機損失。</li></ul><h3 id="策略佈局與未來發展" tabindex="-1">策略佈局與未來發展 <a class="header-anchor" href="#策略佈局與未來發展" aria-label="Permalink to &quot;策略佈局與未來發展&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2026年TGV玻璃穿孔設備下半年量產。Micro LED巨量轉移接合設備驗證中。富臨科技（持股76.8%）提供種子層濺鍍設備。</li><li><strong>深度見解</strong>：東捷從「單機供應商」轉型為「整線方案整合者」，透過集團化與聯盟化提升議價力。轉型尚需2-3年驗證，2026年仍處投入期。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一</strong>：「群創依賴症」——群創為FOPLP最大客戶，但群創已將南科Fab 5出售給日月光。若日月光接手後轉向自有設備或其他供應商（如東京威力、SCREEN），東捷在FOPLP供應鏈的地位將遭邊緣化，此為重大<strong>危機</strong>。此外，群創FOPLP出貨量雖成長但尚未達經濟規模，若技術路徑<strong>脆弱</strong>無法突破良率瓶頸，東捷的先進封裝營收預期將徹底落空。</li><li><strong>空頭風險二</strong>：「中國過半的<strong>困境</strong>」——2025年中國大陸營收佔比52%（2024年僅28%），主因是LED真空設備銷往中國客戶。若美中科技戰升溫或中國LED投資週期<strong>惡化</strong>，此營收將面臨斷崖崩盤。<strong>威脅</strong>在於應收帳款週轉天數持續上升，現金流萎縮將反噬營運。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>年報/財報</strong>：OK — 2025年報（民國114年）第69頁主要客戶資訊、第68頁產品別營收、第69頁地區別資訊；2024年報第71頁</li><li><strong>新聞/媒體</strong>：OK — 經濟日報2026/04/15日月光收購群創Fab 5；Money.udn.com先進封裝設備供應鏈；Digitimes群創FOPLP量產進度</li><li><strong>法說/研究</strong>：OK — poorstock.com 2025法說會紀錄；readmo.cmoney.tw 2026法說會摘要</li><li><strong>關鍵核對碼</strong>： <ul><li>114年營收$2,870,684仟元，客戶A=$419,172(15%)、B=$303,451(11%)、C=$58,610(2%)</li><li>113年營收$2,603,886仟元，客戶B=$947,373(36%)、C=$309,603(12%)、A=$24,226(1%)</li><li>114年地區：中國$1,492,569(52%)、台灣$1,372,424(47.8%)</li><li>113年地區：中國$731,959(28.1%)、台灣$1,833,712(70.4%)</li></ul></li></ul><hr><p><strong>報告寫入路徑</strong>：/Users/kaipro/.openclaw/skills/NEW_Deep32Q/審計報告庫/8064_東捷/20260429/經營組/G10_關鍵合作夥伴與Tier1客戶_投資研究員.md <strong>審計身分</strong>：投資研究員 (finance-investment-researcher) | Deep32Q L3 <strong>數據時效</strong>：截至2025年年報及2026年4月最新公開數據</p>',21)])])}const u=a(o,[["render",l]]);export{g as __pageData,u as default};
